  VALUES (?question) {
    ("How many languages are spoken in Colombia?")
    ("Give me the capitals of all countries in Africa.")
    ("Which countries have more than two official languages?")
  }
  BIND(
    IF(
      ?question = "How many languages are spoken in Colombia?",
      (
        SELECT (COUNT(DISTINCT ?language) AS ?answer) WHERE {
          ?language wdt:P31 wd:Q34770.
          ?language wdt:P17 wd:Q739.
