            ?country wdt:P30 wd:Q15.
            ?country wdt:P36 ?capital.
            SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". ?capital rdfs:label ?capitalLabel. }
          }
        ),
        IF(
          ?question = "Which countries have more than two official languages?",
