    FILTER(?question = "Which U.S. state has been admitted latest?")
  }
  OPTIONAL {
    ?uri3 wdt:P31 wd:Q6256 .
    ?uri3 wdt:P37 ?language .
    FILTER(?question = "Which country has the most official languages?")
  }

  BIND(COALESCE(?uri1, ?uri2, ?uri3) AS ?uri)
}
GROUP BY ?question ?uri
ORDER BY ?question DESC(?dateAdmitted) DESC(COUNT(?language))
LIMIT 3
```

