```PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?question ?answer WHERE {
  VALUES (?question) {
    ("Which Indian company has the most employees?")
    ("Which companies have more than 1 million employees?")
    ("What is the revenue of IBM?")
  }
  BIND(
    IF(?question = "Which Indian company has the most employees?",
      STR(
        CONCAT(
          "SELECT DISTINCT ?uri WHERE { ?uri wdt:P31 wd:Q4830453; wdt:P17 wd:Q668; wdt:P1128 ?employees } ORDER BY DESC(?employees) LIMIT 1"
        )
      ),
      IF(?question = "Which companies have more than 1 million employees?",
        STR(
          CONCAT(
            "PREFIX wdt: <http://www.wikidata.org/prop/direct/>\n",
            "PREFIX wd: <http://www.wikidata.org/entity/>\n",
            "SELECT DISTINCT ?uri WHERE {\n",
            "  ?type wdt:P279* wd:Q4830453 .\n",
            "  ?uri wdt:P31 ?type; wdt:P1128 ?num .\n",
            "  FILTER(?num > 1000000)\n",
            "}"
          )
        ),
        IF(?question = "What is the revenue of IBM?",
          STR(
            CONCAT(
              "SELECT ?o1 WHERE { wd:Q37156 wdt:P2139 ?o1 }"
            )
          ),
          ""
        )
      )
    ) AS ?answer
  )
}
LIMIT 3
```

