  # Official language of Suriname
  wd:Q730 wdt:P37 ?surinameLanguage .

  # Countries that border Iran
  wd:Q794 wdt:P47 ?iranBorders .

  # Country with the most official languages
  {
    SELECT ?countryMostLanguages (COUNT(?language) AS ?langCount) WHERE {
      ?countryMostLanguages wdt:P31 wd:Q6256 .
      ?countryMostLanguages wdt:P37 ?language .
    }
    GROUP BY ?countryMostLanguages
    ORDER BY DESC(?langCount)
    LIMIT 1
  }
}
